#!/bin/zsh
# Claude Code CC Aliases
# Terminal shortcuts to launch Claude with team-specific agent personas
# Generated by AITeamForge installer — uses direct --system-prompt passing
# NOTE: stdin piping (echo | claude --system-prompt -) breaks in tmux contexts

# Installation directory (substituted during install)
AITEAMFORGE_DIR="{{AITEAMFORGE_DIR}}"

# ─────────────────────────────────────────────────────────────────────────────
# Core Infrastructure
# ─────────────────────────────────────────────────────────────────────────────

# Remove any existing cc/ccc aliases before defining functions
unalias cc 2>/dev/null
unalias ccc 2>/dev/null

# Encode working directory to match Claude Code's project directory naming
# /Users/darrenehlers/dev-team → -Users-darrenehlers-dev-team
_cc_encode_project_dir() {
    local dir="${1:-$(pwd)}"
    echo "$dir" | sed 's|/|-|g; s|^-||'
}

# Save the most recent Claude session ID for the current terminal
# Enables per-terminal session resume via ccc
_cc_save_session() {
    [[ -z "$SESSION_CODE" ]] && return 0

    local encoded_dir
    encoded_dir=$(_cc_encode_project_dir)
    local project_dir="$HOME/.claude/projects/-${encoded_dir}"

    [[ ! -d "$project_dir" ]] && return 0

    # Find the most recently modified session .jsonl file
    local latest_file
    latest_file=$(ls -t "$project_dir"/*.jsonl 2>/dev/null | head -1)
    [[ -z "$latest_file" ]] && return 0

    # Staleness guard: only save if file was modified in the last 60 seconds
    local now file_mtime age
    now=$(date +%s)
    file_mtime=$(stat -f %m "$latest_file" 2>/dev/null)
    if [[ -n "$file_mtime" ]]; then
        age=$(( now - file_mtime ))
        if (( age > 60 )); then
            return 0
        fi
    fi

    local session_id
    session_id=$(basename "$latest_file" .jsonl)

    # Validate UUID format
    if [[ "$session_id" =~ ^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$ ]]; then
        mkdir -p "$HOME/.claude/terminal-sessions"
        echo "$session_id" > "$HOME/.claude/terminal-sessions/${SESSION_CODE}"
    fi
}

# Helper: launch Claude Code with a system prompt file
# Uses direct argument passing (NOT stdin piping, which breaks in tmux)
# Set CC_DEBUG=1 for preview only
_cc_launch() {
    local prompt_file="$1"

    # Read .txt file directly — sourcing .sh files breaks in tmux (${0:a:h} resolves wrong)
    local txt_file="${prompt_file%.sh}.txt"

    if [[ ! -f "$txt_file" ]]; then
        echo "ERROR: Prompt file not found: $txt_file" >&2
        return 1
    fi

    CLAUDE_SYSTEM_PROMPT="$(<"$txt_file")"

    if [[ -z "$CLAUDE_SYSTEM_PROMPT" ]]; then
        echo "ERROR: CLAUDE_SYSTEM_PROMPT is empty after reading $txt_file" >&2
        return 1
    fi

    if [[ "$CC_DEBUG" == "1" ]]; then
        echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
        echo "CC_DEBUG=1 — Preview Only"
        echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
        echo "Prompt file: $prompt_file"
        echo "Prompt length: ${#CLAUDE_SYSTEM_PROMPT} chars"
        echo ""
        echo "First 500 chars:"
        echo "${CLAUDE_SYSTEM_PROMPT:0:500}"
        echo "..."
        return 0
    fi

    claude --permission-mode bypassPermissions --append-system-prompt "$CLAUDE_SYSTEM_PROMPT" \
        "If an AMB heartbeat system reminder is present, call mcp__amb__heartbeat first, then introduce yourself briefly."

    _cc_save_session

    if command -v kb-clear &> /dev/null; then
        kb-clear
    fi
}

# Context-aware cc command — detects terminal SESSION_TYPE/SESSION_NAME and
# uses the appropriate persona. Falls back to plain claude if not configured.
cc() {
    if [[ -n "$SESSION_TYPE" && -n "$SESSION_NAME" ]]; then
        local dir="${SESSION_DIR:-$SESSION_TYPE}"
        local prompt_file="$AITEAMFORGE_DIR/${dir}/scripts/prompts/${SESSION_TYPE}-${SESSION_NAME}-prompt.sh"
        if [[ -f "${prompt_file%.sh}.txt" ]]; then
            _cc_launch "$prompt_file"
            return
        fi
    fi
    claude --permission-mode bypassPermissions "$@"
}

# Resume the most recent Claude session for THIS terminal
# Uses stored session ID instead of --continue (which picks most recent globally)
ccc() {
    local session_file="$HOME/.claude/terminal-sessions/${SESSION_CODE}"

    if [[ -n "$SESSION_CODE" && -f "$session_file" ]]; then
        local session_id
        session_id=$(<"$session_file")
        if [[ -n "$session_id" ]]; then
            claude --permission-mode bypassPermissions --resume "$session_id"
            _cc_save_session
            if command -v kb-clear &> /dev/null; then
                kb-clear
            fi
            return
        fi
    fi

    claude --permission-mode bypassPermissions --continue
    _cc_save_session
    if command -v kb-clear &> /dev/null; then
        kb-clear
    fi
}

